		SELECT COUNT(*)
        FROM questions q
        WHERE q.id = #{questionId}
          AND q.delflag = 'N'
          AND (
              q.visibility = 'PUBLIC'
              OR EXISTS (
                  SELECT 1 FROM team_members tm
                  WHERE tm.team_id = q.team_id
                    AND tm.user_id = #{userId}
                    AND tm.delflag = 'N'
              )
          )

mapper.insert:
INSERT INTO likes (user_id, target_id, target_type, created_at)
SELECT #{userId}, #{targetId}, #{targetType}, NOW()
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1 FROM likes
    WHERE user_id = #{userId}
      AND target_id = #{targetId}
      AND target_type = #{targetType}
)

mapper.update:
UPDATE questions
SET like_count = (
    SELECT COUNT(*) FROM likes
    WHERE target_type = 'QUE' AND target_id = #{questionId}
)
WHERE id = #{questionId}

UPDATE answers
SET like_count = (
    SELECT COUNT(*) FROM likes
    WHERE target_type = 'ANS' AND target_id = #{answerId}
)
WHERE id = #{answerId}
